/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // --- Step 1: Calculate shortest path costs when empty-handed (Travel Cost A) ---
    // The cost of an edge (u, v) without apples is cost.
    // We need the shortest path distance from any node to any other node, considering only 'cost'.

    // Initialize distances for the "empty-handed" travel graph (Graph A)
    // distA[i][j] = shortest path cost from i to j when empty-handed.
    const INF = 1e18; // A large number representing infinity
    const distA = Array(n).fill(0).map(() => Array(n).fill(INF));
    for (let i = 0; i < n; i++) {
        distA[i][i] = 0;
    }

    // Build adjacency list for Graph A
    const adjA = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        // Road is bidirectional
        adjA[u].push({ node: v, weight: cost });
        adjA[v].push({ node: u, weight: cost });
    }

    // Floyd-Warshall or repeated Dijkstra. Since N <= 1000, Floyd-Warshall O(N^3) might be too slow (10^9).
    // Dijkstra from every node O(N * (E + N log N)). E is O(N^2) max, but here E is small (<= 2000).
    // N * (2000 + 1000 log 1000) approx 1000 * (2000 + 10000) = 1.2 * 10^7 operations. Dijkstra is fine.

    const dijkstra = (startNode, graphAdj) => {
        const dist = Array(n).fill(INF);
        dist[startNode] = 0;

        // Priority Queue: stores [distance, node]
        // Using an array simulation for simplicity since N is not extremely large, but a proper heap is better.
        // For competitive programming in JS, a simple array sort/pop might suffice given the constraints.
        let pq = [[0, startNode]]; // [cost, node]

        while (pq.length > 0) {
            // Simple extraction of minimum: O(k) where k is pq size
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > dist[u]) continue;

            for (const edge of graphAdj[u]) {
                const v = edge.node;
                const weight = edge.weight;

                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.push([dist[v], v]);
                }
            }
        }
        return dist;
    };

    // Calculate all-pairs shortest path for Graph A (Empty-handed travel)
    for (let i = 0; i < n; i++) {
        distA[i] = dijkstra(i, adjA);
    }

    // --- Step 2: Calculate shortest path costs when carrying apples (Travel Cost B) ---
    // The cost of an edge (u, v) with apples is cost * tax.
    // We need the shortest path distance from any node to any other node, considering only 'cost * tax'.

    // Initialize distances for the "carrying-apples" travel graph (Graph B)
    // distB[i][j] = shortest path cost from i to j when carrying apples.
    const distB = Array(n).fill(0).map(() => Array(n).fill(INF));
    for (let i = 0; i < n; i++) {
        distB[i][i] = 0;
    }

    // Build adjacency list for Graph B
    const adjB = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        const costTax = cost * tax;
        // Road is bidirectional
        adjB[u].push({ node: v, weight: costTax });
        adjB[v].push({ node: u, weight: costTax });
    }

    // Calculate all-pairs shortest path for Graph B (Carrying apples)
    for (let i = 0; i < n; i++) {
        distB[i] = dijkstra(i, adjB);
    }

    // --- Step 3: Calculate the minimum cost for each starting shop i ---
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy at shop i directly
        let min_cost = prices[i];

        // Option 2: Go to shop j (empty-handed), buy at j, return to i (carrying apples)
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // Total Cost = (Travel i -> j empty) + prices[j] + (Travel j -> i carrying)

            // Travel i -> j (Empty-handed): distA[i][j]
            const travel_empty = distA[i][j];

            // Travel j -> i (Carrying apples): distB[j][i]
            const travel_carrying = distB[j][i];

            // Check for reachability
            if (travel_empty !== INF && travel_carrying !== INF) {
                const total_cost = travel_empty + prices[j] + travel_carrying;
                if (total_cost < min_cost) {
                    min_cost = total_cost;
                }
            }
        }
        ans[i] = min_cost;
    }

    return ans;
}

