import java.util.PriorityQueue
import java.util.Comparator

data class Edge(val node: Int, val weight: Long)

/**
 * Solves the minimum cost to acquire apples problem.
 */
fun solve(n: Long, prices: Array<Long>, roads: Array<Array<Long>>): Array<Long> {
    val N = n.toInt()
    val priceArr = prices
    val roadList = roads

    val INF = 1_000_000_000_000_000_000L // 10^18

    // --- Graph Construction and Dijkstra's Helper ---

    // Dijkstra's algorithm implementation
    fun dijkstra(startNode: Int, adj: Array<MutableList<Edge>>): LongArray {
        val dist = LongArray(N) { INF }
        dist[startNode] = 0L

        // PriorityQueue stores pairs: [distance, node]
        // We use an array for simplicity, comparing by distance (first element).
        val pq = PriorityQueue<Pair<Long, Int>>(compareBy { it.first })
        pq.add(Pair(0L, startNode))

        while (pq.isNotEmpty()) {
            val (d, u) = pq.poll()

            if (d > dist[u]) continue

            for (edge in adj[u]) {
                val v = edge.node
                val weight = edge.weight

                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight
                    pq.add(Pair(dist[v], v))
                }
            }
        }
        return dist
    }

    // --- Step 1: Calculate shortest path costs when empty-handed (Graph A) ---

    val adjA = Array(N) { mutableListOf<Edge>() }
    for (road in roadList) {
        val u = road[0].toInt()
        val v = road[1].toInt()
        val cost = road[2]
        // Road is bidirectional, cost is used for empty travel
        adjA[u].add(Edge(v, cost))
        adjA[v].add(Edge(u, cost))
    }

    // distA[i] is the array of shortest paths starting from i, empty-handed
    val distA = Array(N) { LongArray(N) }
    for (i in 0 until N) {
        distA[i] = dijkstra(i, adjA)
    }

    // --- Step 2: Calculate shortest path costs when carrying apples (Graph B) ---

    val adjB = Array(N) { mutableListOf<Edge>() }
    for (road in roadList) {
        val u = road[0].toInt()
        val v = road[1].toInt()
        val cost = road[2]
        val tax = road[3]

        // Cost when carrying apples = cost * tax
        val costTax = cost * tax 

        // Road is bidirectional, costTax is used for carrying travel
        adjB[u].add(Edge(v, costTax))
        adjB[v].add(Edge(u, costTax))
    }

    // distB[j] is the array of shortest paths starting from j, carrying apples
    val distB = Array(N) { LongArray(N) }
    for (j in 0 until N) {
        distB[j] = dijkstra(j, adjB)
    }

    // --- Step 3: Calculate the minimum cost for each starting shop i ---

    val ans = LongArray(N)

    for (i in 0 until N) {
        // Option 1: Buy at shop i directly
        var minCost = priceArr[i]

        // Option 2: Go to shop j (empty-handed), buy at j, return to i (carrying apples)
        for (j in 0 until N) {
            if (i == j) continue

            // Total Cost = (Travel i -> j empty) + prices[j] + (Travel j -> i carrying)

            // Travel i -> j (Empty-handed): distA[i][j]
            val travelEmpty = distA[i][j]

            // Travel j -> i (Carrying apples): distB[j][i]
            val travelCarrying = distB[j][i]

            // Check for reachability
            if (travelEmpty != INF && travelCarrying != INF) {
                // Note: prices[j] is already Long
                val totalCost = travelEmpty + priceArr[j] + travelCarrying
                if (totalCost < minCost) {
                    minCost = totalCost
                }
            }
        }
        ans[i] = minCost
    }

    return ans
}
